const {
  FILE_OWNERS,
  STYLE_EXTENSIONS,
  SCRIPT_EXTENSIONS,
} = require('../../constants/file');
const {
  BASE_HOOKS_NAMING_REGEX,
  HTTP_ERROR_PAGE_FILES_IN_ROOT_REGEX,
  FILE_IN_ROOT_REGEX,
  ROUTER_CONFIG_NAMING_REGEX,
} = require('../../constants/regexs');
const { NORDIC_PAGES_PATH } = require('../../constants/files-discovery');
const { log } = require('../logger');
const { getFilePageMember } = require('./page-member');

/**
 * @typedef { keyof typeof import('../../constants/device').DEVICE_TYPES } DeviceType
 * @typedef { keyof typeof FILE_OWNERS } FileOwnerType
 */

/**
 * Checks if the owner is valid for the file received.
 * The owner is invalid when:
 * - The owner is empty
 * - Or the owner is the base hooks file and the file is not located in the root's directory
 * @param { FileOwnerType | undefined } owner - Owner of the file or undefined
 * @param { string } filePath
 *
 * @example
 * validateOwner(FILE_OWNERS.navigablePage, 'product/[id].ts') => Do nothing
 * validateOwner(FILE_OWNERS.baseHooks, '_hooks.server.js') => Do nothing
 * validateOwner(FILE_OWNERS.routerConfig, '_router.config.js') => Do nothing
 * validateOwner(FILE_OWNERS.baseHooks, 'help/_hooks.server.ts') => Throws error
 * validateOwner(FILE_OWNERS.routerConfig, 'help/_router.config.js') => Throws error
 * validateOwner(undefined, 'data.json') => Throws error
 */
const validateOwner = (owner, filePath) => {
  if (!owner) {
    throw new Error(
      `The file ${filePath} doesn't match any of the supported ` +
        `extensions for scripts (${SCRIPT_EXTENSIONS.join(
          ',',
        )}) or styles (${STYLE_EXTENSIONS.join(',')}).`,
    );
  }

  if (
    [FILE_OWNERS.baseHooks, FILE_OWNERS.routerConfig].includes(owner) &&
    !FILE_IN_ROOT_REGEX.test(filePath)
  ) {
    log.warn(
      `Expected to find Nordic Pages ${owner === FILE_OWNERS.baseHooks ? 'base server hooks' : 'router config'} file in the root of ` +
        `${NORDIC_PAGES_PATH} but was found in: ${filePath}`,
    );
  }
};

/**
 * Looks for the owner of the file path received.
 * If the owner is invalid, an error is thrown.
 * @param { string } filePath - File path to analize
 * @returns { FileOwnerType } Owner value (only when valid)
 *
 * @example
 * getFileOwner('product/[id].ts') => FILE_OWNERS.navigablePage
 * getFileOwner('_hooks.server.js') => FILE_OWNERS.baseHooks
 * getFileOwner('_router.config.js') => FILE_OWNERS.routerConfig
 * getFileOwner('404.ts') => FILE_OWNERS.httpErrorPage
 * getFileOwner('data.json') => Throws error
 */
const getFileOwner = (filePath) => {
  /**
   * @type {FileOwnerType | undefined}
   */
  let owner;

  if (ROUTER_CONFIG_NAMING_REGEX.test(filePath)) {
    owner = FILE_OWNERS.routerConfig;
  } else if (BASE_HOOKS_NAMING_REGEX.test(filePath)) {
    owner = FILE_OWNERS.baseHooks;
  } else if (HTTP_ERROR_PAGE_FILES_IN_ROOT_REGEX.test(filePath)) {
    owner = FILE_OWNERS.httpErrorPage;
  } else if (getFilePageMember(filePath)) {
    owner = FILE_OWNERS.navigablePage;
  }

  validateOwner(owner, filePath);

  return owner;
};

module.exports = {
  getFileOwner,
  validateOwner,
};
